// data/serviceContent.ts
// Hand-written deep service pillar content for SEIS Accountants.
//
// Each pillar carries:
//   intro:           Top-of-page positioning paragraphs (3 paragraphs)
//   benefits:        4 cards showing why specialism matters
//   candidateIntro:  Lead-in to candidate list
//   candidates:      Who specifically benefits from the service
//   process:         4-step engagement process
//   deepDive:        Long-form prose covering mechanics and current rules
//   edgeCases:       Nuance and "where the standard playbook doesn't apply"
//   workedExamples:  Named scenarios with concrete numbers
//
// All UK-national positioning. British English throughout. No em dashes.

export interface WorkedExample {
  title: string;
  body: string;
}

export interface ServiceContent {
  intro: string[];
  benefits: { title: string; desc: string }[];
  candidateIntro: string;
  candidates: string[];
  process: { title: string; desc: string }[];
  deepDive: string[];
  edgeCases: string[];
  workedExamples: WorkedExample[];
}

